// CareTipsList.jsx
import React, { useEffect, useState } from 'react';
import axios from 'axios';

function CareTipsList({ onSelect }) {
  const [tips, setTips] = useState([]);
  const [filter, setFilter] = useState('All');
  const topics = ['All', 'Watering', 'Sunlight', 'Soil', 'Pruning', 'Temperature'];

  useEffect(() => {
    axios.get('http://localhost:5000/api/caretips')
      .then(res => setTips(res.data))
      .catch(() => alert('Failed to fetch care tips'));
  }, []);

  const filteredTips = tips.filter(tip =>
    filter === 'All' || tip.topic.toLowerCase() === filter.toLowerCase()
  );

  return (
    <div>
      <h2>Plant Care Tips</h2>
      <div>
        {topics.map(t => (
          <button
            key={t}
            onClick={() => setFilter(t)}
            style={{
              margin: '5px',
              backgroundColor: filter === t ? 'green' : 'lightgray',
              color: filter === t ? 'white' : 'black',
            }}
          >
            {t}
          </button>
        ))}
      </div>

      <div>
        {filteredTips.map((tip, index) => (
          <div
            key={index}
            onClick={() => onSelect(tip._id)}
            style={{
              border: '1px solid #ccc',
              margin: '10px',
              padding: '10px',
              cursor: 'pointer',
              backgroundColor: '#f9f9f9',
            }}
          >
            <h3>{tip.title} - {tip.topic}</h3>
            <p>{tip.summary}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default CareTipsList;
